import { createFileRoute } from "@tanstack/react-router";
import { useEffect, useRef } from "react";

export const Route = createFileRoute("/gate")({
  head: () => ({ meta: [{ title: "ساعِد — دخول المنصة" }] }),
  component: Gate,
});

const STYLES = `
*{margin:0;padding:0;box-sizing:border-box}
html,body{height:100%;font-family:'Tajawal',sans-serif;direction:rtl;overflow:hidden}

.bg{position:fixed;inset:0;background:linear-gradient(135deg,#071a0f 0%,#0d3322 40%,#163d28 70%,#0a2518 100%)}
.bg-grid{position:fixed;inset:0;background-image:linear-gradient(rgba(45,122,82,.07) 1px,transparent 1px),linear-gradient(90deg,rgba(45,122,82,.07) 1px,transparent 1px);background-size:50px 50px}
.bg-glow{position:fixed;width:600px;height:600px;border-radius:50%;background:radial-gradient(circle,rgba(45,122,82,.12) 0%,transparent 70%);top:-100px;right:-100px;pointer-events:none}
.bg-glow2{position:fixed;width:400px;height:400px;border-radius:50%;background:radial-gradient(circle,rgba(201,168,76,.06) 0%,transparent 70%);bottom:-50px;left:-50px;pointer-events:none}

#gate{position:fixed;inset:0;z-index:100;display:flex;align-items:center;justify-content:center;padding:20px}

.gate-card{background:rgba(255,255,255,.04);backdrop-filter:blur(24px);border:1px solid rgba(255,255,255,.1);border-radius:24px;padding:44px 40px;width:100%;max-width:420px;text-align:center;animation:slideUp .5s cubic-bezier(.22,1,.36,1) both}
@keyframes slideUp{from{opacity:0;transform:translateY(24px)}to{opacity:1;transform:translateY(0)}}

.gate-logo{width:90px;height:auto;margin:0 auto 20px;filter:brightness(0) invert(1);opacity:.95}

.gate-badge{display:inline-flex;align-items:center;gap:7px;background:rgba(201,168,76,.12);border:1px solid rgba(201,168,76,.25);border-radius:20px;padding:5px 16px;margin-bottom:22px}
.gate-badge-dot{width:7px;height:7px;border-radius:50%;background:#c9a84c;animation:blink 1.8s ease-in-out infinite}
@keyframes blink{0%,100%{opacity:1}50%{opacity:.3}}
.gate-badge-text{font-size:.8rem;font-weight:600;color:#e8c96e;letter-spacing:.04em}

.gate-title{font-size:1.75rem;font-weight:800;color:rgba(255,255,255,.95);line-height:1.3;margin-bottom:10px}
.gate-sub{font-size:.9rem;color:rgba(255,255,255,.45);line-height:1.65;margin-bottom:28px}

.build-progress{background:rgba(255,255,255,.07);border-radius:20px;height:6px;margin-bottom:8px;overflow:hidden}
.build-bar{height:100%;border-radius:20px;background:linear-gradient(90deg,#2d7a52,#4a9e70,#c9a84c);width:72%;animation:grow .8s ease .3s both}
@keyframes grow{from{width:0}to{width:72%}}
.build-pct{font-size:.74rem;color:rgba(255,255,255,.3);text-align:left;margin-bottom:26px}

.pass-input{width:100%;padding:14px 18px;border-radius:10px;background:rgba(255,255,255,.07);border:1.5px solid rgba(255,255,255,.12);color:white;font-family:'Tajawal',sans-serif;font-size:1rem;outline:none;text-align:center;letter-spacing:.12em;transition:border-color .2s,background .2s;direction:ltr;margin-bottom:12px}
.pass-input::placeholder{color:rgba(255,255,255,.25);letter-spacing:.04em}
.pass-input:focus{border-color:rgba(45,122,82,.6);background:rgba(255,255,255,.1)}
.pass-input.error{border-color:rgba(220,38,38,.6);animation:shake .35s ease}
@keyframes shake{0%,100%{transform:translateX(0)}25%{transform:translateX(-6px)}75%{transform:translateX(6px)}}

.pass-btn{width:100%;padding:14px;border-radius:10px;background:linear-gradient(135deg,#1a5c3a,#2d7a52);color:white;border:none;font-family:'Tajawal',sans-serif;font-size:1rem;font-weight:700;cursor:pointer;transition:all .2s;letter-spacing:.02em}
.pass-btn:hover{background:linear-gradient(135deg,#2d7a52,#4a9e70);transform:translateY(-1px);box-shadow:0 6px 20px rgba(45,122,82,.35)}
.pass-btn:active{transform:translateY(0)}

.pass-err{font-size:.8rem;color:#f87171;margin-top:10px;display:none;animation:fadeIn .2s ease}
@keyframes fadeIn{from{opacity:0}to{opacity:1}}
.pass-err.show{display:block}

.preview-chips{display:flex;flex-wrap:wrap;gap:8px;justify-content:center;margin-top:22px}
.chip{background:rgba(255,255,255,.05);border:1px solid rgba(255,255,255,.08);border-radius:20px;padding:5px 13px;font-size:.75rem;color:rgba(255,255,255,.4)}

.gate-footer{margin-top:24px;font-size:.75rem;color:rgba(255,255,255,.2);border-top:1px solid rgba(255,255,255,.07);padding-top:16px}
.gate-footer span{color:rgba(201,168,76,.5);font-weight:600}
`;
const BODY = `<div class="bg"></div>
<div class="bg-grid"></div>
<div class="bg-glow"></div>
<div class="bg-glow2"></div>

<div id="gate">
  <div class="gate-card">
    <img src="data:image/png;base64," alt="ساعِد" class="gate-logo">

    <div class="gate-badge">
      <div class="gate-badge-dot"></div>
      <span class="gate-badge-text">قيد الإنشاء</span>
    </div>

    <div class="gate-title">المنصة قادمة قريباً</div>
    <div class="gate-sub">نعمل على بناء منصة إدارية متكاملة للجمعيات الخيرية.<br>للوصول المبكر أدخل كلمة المرور.</div>

    <div class="build-progress"><div class="build-bar"></div></div>
    <div class="build-pct">اكتملت نسبة 72% من التطوير</div>

    <input class="pass-input" id="passInput" type="password" placeholder="كلمة المرور" autocomplete="off" onkeydown="if(event.key==='Enter') tryPass()">
    <button class="pass-btn" onclick="tryPass()">دخول المنصة ←</button>
    <div class="pass-err" id="passErr">كلمة المرور غير صحيحة، حاول مجدداً</div>

    <div class="preview-chips">
      <span class="chip">📋 ملف الجمعية</span>
      <span class="chip">✅ لوحة المهام</span>
      <span class="chip">💳 تتبع التبرعات</span>
      <span class="chip">✦ محتوى AI</span>
      <span class="chip">👥 إدارة الفريق</span>
    </div>

    <div class="gate-footer">ساعِد · <span>The Bright Station</span> · جميع الحقوق محفوظة</div>
  </div>
</div>

`;
const SCRIPT = `
var DEV_PASS = 'saaid2025dev'

function tryPass() {
  var val = document.getElementById('passInput').value
  var input = document.getElementById('passInput')
  var errEl = document.getElementById('passErr')
  if (val === DEV_PASS) {
    sessionStorage.setItem('saaid_devAccess', DEV_PASS)
    document.querySelector('.pass-btn').textContent = '✓ جاري الدخول...'
    input.style.borderColor = 'rgba(45,122,82,.7)'
    setTimeout(function() { window.location.href = 'association-dashboard.html' }, 600)
  } else {
    input.classList.add('error')
    errEl.classList.add('show')
    setTimeout(function() { input.classList.remove('error') }, 400)
    input.value = ''
    setTimeout(function() { input.focus() }, 100)
  }
}
`;

function Gate() {
  const ref = useRef<HTMLDivElement>(null);
  useEffect(() => {
    document.documentElement.setAttribute("dir", "rtl");
    document.documentElement.setAttribute("lang", "ar");
    if (!SCRIPT.trim() || !ref.current) return;
    const s = document.createElement("script");
    s.text = SCRIPT;
    ref.current.appendChild(s);
    return () => { try { ref.current?.removeChild(s); } catch {} };
  }, []);
  return (
    <>
      <style dangerouslySetInnerHTML={{ __html: STYLES }} />
      <div ref={ref} dangerouslySetInnerHTML={{ __html: BODY }} />
    </>
  );
}
